+	if err := v.Set("0"); err != nil {
+		t.Fatalf("Set(\"0\") error: %v", err)
+	}
+	if enabled {
+		t.Fatal("enabled should be false after Set(\"0\")")
+	}
+	if dur != 0 {
+		t.Fatalf("duration after Set(\"0\") = %v, want 0", dur)
