+
+	if err := v.Set("10s"); err != nil {
+		t.Fatalf("Set(\"10s\") error: %v", err)
+	}
+	if !enabled {
+		t.Fatal("enabled should be true after Set(\"10s\")")
+	}
+	if dur != 10*time.Second {
+		t.Fatalf("duration after Set(\"10s\") = %v, want 10s", dur)
